                        </svg>
                        <div>
                             <h3 className="font-semibold">AI-powered College Matching</h3>
                        </div>
                    </div>
                     <div className="flex items-start gap-3">
                         <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6 text-white shrink-0">
                          <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75 11.25 15 15 9.75M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z" />
                        </svg>
                        <div>
                             <h3 className="font-semibold">Neutral, Unbiased Expert Guidance</h3>
                        </div>
                    </div>
                </div>

                {/* Search Bar - Visual Only */}
                <div className="mt-10 relative max-w-xl">
                   <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                     {/* Search Icon */}
                   </div>
                   <input
                      type="text"
                      disabled
                      className="block w-full rounded-full border-0 py-4 pl-6 pr-14 text-gray-900 shadow-sm ring-1 ring-inset ring-gray-300 placeholder:text-gray-400 bg-white/10 backdrop-blur-md text-white placeholder:text-gray-200 focus:ring-2 focus:ring-inset focus:ring-indigo-600 sm:text-sm sm:leading-6"
                      placeholder="Search College, Course, Exams or 10,000+ Verified Reviews..."
                    />
                    <div className="absolute inset-y-1 right-1">
                        <div className="h-fullAspect-square bg-indigo-600 rounded-full p-2.5 flex items-center justify-center">
                             <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5 text-white">
                              <path strokeLinecap="round" strokeLinejoin="round" d="m21 21-5.197-5.197m0 0A7.5 7.5 0 1 0 5.196 5.196a7.5 7.5 0 0 0 10.607 10.607Z" />
