                        </div>
                    </div>
                </div>
                <p className="mt-2 text-xs text-gray-400">Every review is manually verified for authenticity.</p>


                {/* Buttons Action Area - MODIFIED to show only Start Assessment */}
                <div className="mt-10 flex gap-4">
                     <button
                        onClick={() => setStep("profile")}
                        className="rounded-full bg-white px-8 py-3.5 text-base font-bold text-indigo-900 shadow-sm hover:bg-gray-100 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-white transition flex items-center gap-2"
                      >
                       Start Assessment & Earn Rewards
                       <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-5 h-5">
                          <path fillRule="evenodd" d="M3 10a.75.75 0 0 1 .75-.75h10.638L10.23 5.29a.75.75 0 1 1 1.04-1.08l5.5 5.25a.75.75 0 0 1 0 1.08l-5.5 5.25a.75.75 0 1 1-1.04-1.08l4.158-3.96H3.75A.75.75 0 0 1 3 10Z" clipRule="evenodd" />
                        </svg>

                      </button>
                      <button className="rounded-full bg-indigo-600/30 border border-indigo-500/50 px-6 py-3.5 text-base font-semibold text-white shadow-sm hover:bg-indigo-600/40 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-500 transition border-1">
                        Find College
                      </button>
                       <button className="rounded-full bg-transparent border border-white/30 px-6 py-3.5 text-base font-semibold text-white shadow-sm hover:bg-white/10 transition">
                        Get Expert Counselling
                      </button>
                </div>


                {/* Bottom Trust Indicators */}
                <div className="mt-16 border-t border-white/10 pt-8 flex flex-wrap gap-8 md:gap-16">
                    <div>
                         <div className="text-2xl font-bold text-white">12,000+</div>
                         <div className="text-sm text-gray-400">Verified Reviews</div>
                    </div>
                     <div>
                         <div className="text-2xl font-bold text-white">3,200</div>
                         <div className="text-sm text-gray-400">Colleges</div>
                    </div>
                     <div>
                         <div className="text-2xl font-bold text-white">87%</div>
                         <div className="text-sm text-gray-400">Student Satisfaction</div>
                    </div>
                </div>

              </div>
            </div>
          </div>
        )}

        {step === "profile" && (
          <div className="py-12 bg-gray-50 min-h-screen">
             <div className="max-w-4xl mx-auto px-4">
                <ProfileForm onSubmit={handleProfileSubmit} setAlert={setAlert} />
             </div>
          </div>
        )}

        {step === "questions" && (
           <div className="py-12 bg-gray-50 min-h-screen">
             <div className="max-w-4xl mx-auto px-4">
                  <Questionnaire
                    questions={questions}
                    onSubmit={handleAssessmentSubmit}
                  />
             </div>
          </div>
        )}
      </AnimatedPageWrapper>
    </div>
  );
}
